```class Solution {
    public double minTime(int n, int k, int m, int[] time, double[] mul) {
        int n_minus_k = n - k;
        int[] stage_index = new int[m];
        double[] time_sum = new double[m];
        double result = Double.POSITIVE_INFINITY;

        for (int i = 0; i < m; i++) {
            stage_index[i] = i;
            time_sum[i] = time[stage_index[i] * mul[i];
        }

        for (int i = 0; i < n_minus_k; i++) {
            int stage_index_return = i;
            double time_sum_return = time_sum[stage_index_return] * mul[stage_index_return];
            for (int j = 0; j < m; j++) {
                int stage_index_return_j = stage_index[j];
                double time_sum_return_j = time_sum[stage_index_return_j] * mul[stage_index_return_j];
                if (time_sum_return_j < result) {
                    result = time_sum_return_j;
                    stage_index_return = stage_index_return_j;
                    time_sum_return = time_sum_return_j * mul[stage_index_return];
                }
            }
        }
        return result;
    }

